func unsafeWrapBaseSrc(base *gobject.ObjectInstance) *BaseSrcInstance {
	return &BaseSrcInstance{
		ElementInstance: gst.ElementInstance{
			ObjectInstance: gst.ObjectInstance{
				InitiallyUnownedInstance: gobject.InitiallyUnownedInstance{
					ObjectInstance: *base,
				},
			},
		},
	}
}

func init() {
	gobject.RegisterObjectCasting(
		TypeBaseSrc,
		func (inst *gobject.ObjectInstance) gobject.Object {
			return unsafeWrapBaseSrc(inst)
		},
	)
}

func marshalBaseSrcInstance(p unsafe.Pointer) (any, error) {
	return gobject.ValueFromNative(p).Object(), nil
}

// UnsafeBaseSrcFromGlibNone is used to convert raw GstBaseSrc pointers to go while taking a reference and attaching a finalizer. This is used by the bindings internally.
